VALUES
  ('policepromo-8b7f1efc-moex-00079', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者，得依法提起撤銷訴訟？', '["不服私立大學教師評審委員會所作成教師不予升等評審決定", "已歇業或破產後之雇主，不服勞動部勞工保險局動用工資墊償基金後仍代為向其求償積欠工資之通知", "地方居民不服地方政府廢止既成道路公告", "地方居民不服都市計畫主要計畫定期通盤檢討之公告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00080', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["行政機關基於法定職權，得以行政契約與人民約定由對造為特定用途之給付，而行政機關亦負相對 之給付義務", "為執行公法法規，行政機關本應作成行政處分者，亦得以行政契約代替", "行政機關為防止或除去對公益之重大危害，終止與人民所締結之行政契約時，行政契約相對人可提 請課以義務訴訟，要求行政機關補償其因此所受之財產上損失", "對於民間參與公共建設投資契約，行政機關得準用政府採購法處理招標、審標規定以甄選或其他競 爭方式決定該行政契約最優申請案件申請人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00081', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬行政契約？', '["全民健康保險特約", "退除役軍職人員與臺灣銀行股份有限公司訂立優惠存款契約", "衛生福利部重點科別培育公費醫學生契約書", "公立學校教師聘約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00082', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬行政上事實行為？', '["對於陳情事件所為函覆", "對於公職人員財產申報資料進行查詢", "對於違規停放車輛實施拖吊保管", "警察責令擅自變更電動二輪車燈光裝置車輛所有人限期改正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00083', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '甲繼承父親座落新北市未經合法登記，亦無合法建造執照及使用執照之房屋，新北市政府已以甲為受 文者寄發「違章建築拆除通知書」，逕認定該房屋為依法不得補辦建造執照手續之違章建築，將於該 通知書所載期日予以拆除。下列敘述何者錯誤？', '["該「違章建築拆除通知書」係具有確認及下命性質之行政處分", "甲如不服該「違章建築拆除通知書」，於系爭房屋未遭拆除前，可向內政部提起訴願", "鄰人乙如發現該「違章建築拆除通知書」所記載房屋座落地址誤植為其所有房屋，於執行程序終結 前，得依行政執行法第9條向新北市政府聲明異議", "承上，鄰人乙如主張該「違章建築拆除通知書」為無效行政處分，得逕向臺北高等行政法院提起確 認行政處分無效訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00084', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於政府資訊公開之敘述，下列何者正確？', '["人民請求政府機關提供之資訊，如已歸檔者則屬檔案法所稱之檔案，應優先適用政府資訊公開法處理", "人民申請公開之資訊，如具檔案性質者，政府機關除得適用檔案法第18條規定外，亦得適用性質相 同之政府資訊公開法第18條第1項各款規定據以拒絕提供", "政府資訊中含有限制公開或不予提供之事項，應予以全部遮蔽，採取防免揭露處置，以達到保密效果", "人民申請提供之資訊包括涉及專門知識、技能或資格所為之考試、檢定或鑑定等有關資料，其公開 或提供將影響其公正效率之執行者，應全部不予提供"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00085', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '建築法規定建築物所有權人、使用人應維護建築物合法使用與其構造及設備安全；違反前述義務或擅 自未經核准變更使用擅自使用建築物者，由直轄市或縣（市）政府處建築物所有權人、使用人新臺幣 6萬元以上30萬元以下罰鍰，並限期改善或補辦手續，屆期仍未改善或補辦手續而繼續使用者，得連 續處罰，並限期停止其使用。下列敘述何者錯誤？', '["房屋出租後，承租人擅自變更房屋防火設計時，直轄市或縣（市）政府依據上開規定亦可對承租人 進行裁罰", "經法院拍賣取得違章建築房屋之拍定人，依法仍負有維護建築物合法使用與其構造及設備安全之狀 態責任", "違章建築所有權人未依直轄市或縣（市）政府所發拆除通知單自行拆除，僅對後續所發「違章建築 拆除時間通知單」提起訴願時，訴願機關應予不受理", "違章建築承租人對於直轄市或縣（市）政府所為新臺幣6萬元罰鍰有所不服而向內政部提起訴願時， 應暫停罰鍰處分之執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00086', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於行政罰之敘述，下列何者正確？', '["中央或地方機關或其他公法組織違反行政法上義務者，不罰", "於設有代表人或管理人之非法人團體，或法人以外之其他私法組織，違反行政法上義務者，不罰代 表人或管理人", "違反行政法上義務應受法定最高額新臺幣5千元以下罰鍰之處罰，其情節輕微，認以不處罰為適當 者，得免予處罰", "不屬於受處罰者所有之物，因所有人之故意或重大過失，致使該物成為違反行政法上義務行為之工 具者，仍得裁處沒入"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00087', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者，相當於訴願程序？', '["稅捐稽徵法規定之申請復查程序", "學生申訴程序", "政府採購爭議之審議判斷程序", "公務員懲戒程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00088', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '行政機關作成行政處分未記明理由時，下列敘述何者錯誤？', '["未限制人民權益之書面行政處分，縱未記明理由，仍為有效", "經公告或刊登政府公報或新聞紙之一般處分，無須記明理由", "得不經訴願程序者，得於行政訴訟一審程序終結前，記明理由補正之", "得於訴願程序終結前，記明理由補正之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
